// Pinga 3 servicos: Evolution, Supabase REST, e checa outbox atrasada
const results = { ts: new Date().toISOString(), services: {} };

// 1. Evolution API
try {
  const evo = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://n8n_evolution-api:8080/instance/connectionState/mira-mirian',
    headers: { apikey: '429683C4C977415CAAFCCE10F7D57E11' },
    timeout: 10000
  });
  results.services.evolution = {
    ok: evo?.instance?.state === 'open',
    state: evo?.instance?.state || 'unknown'
  };
} catch(e) {
  results.services.evolution = { ok: false, error: e.message.slice(0, 100) };
}

// 2. Supabase REST (ping simples)
try {
  const sb = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/rpc/wa_pro_my_quota',
    headers: {
      'Content-Type': 'application/json',
      'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0'
    },
    body: { p_phone: '5544998787673' },
    timeout: 10000
  });
  results.services.supabase = { ok: true };
} catch(e) {
  results.services.supabase = { ok: false, error: e.message.slice(0, 100) };
}

// 3. Outbox atrasada (msgs queued ha mais de 10min = processor pode ter parado)
try {
  const ob = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://oqboitkpcvuaudouwvkl.supabase.co/rest/v1/wa_outbox?status=eq.queued&scheduled_at=lt.' + new Date(Date.now() - 10*60*1000).toISOString() + '&select=id&limit=1',
    headers: {
      'apikey': 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0',
      'Authorization': 'Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im9xYm9pdGtwY3Z1YXVkb3V3dmtsIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzQ0NTgyMzQsImV4cCI6MjA5MDAzNDIzNH0.8d1HT8GTxIVsaTtl9eOiijDkWUVDLaTv2W4qahmI8w0'
    },
    timeout: 10000
  });
  results.services.outbox = {
    ok: !ob || ob.length === 0,
    stale_count: ob ? ob.length : 0
  };
} catch(e) {
  results.services.outbox = { ok: true, note: 'check failed but not critical' };
}

// Verifica se algum falhou
const failed = Object.entries(results.services).filter(([k,v]) => !v.ok);
results.has_failure = failed.length > 0;
results.failed_services = failed.map(([k]) => k);

return [{ json: results }];

